    ('cat_feelings_faces_books', 9, 9, 'visible', true, true, 'Best for farm face flaps', 'Spot Goes to the Farm', 'Eric Hill', 'Bookshop.org UK', 'https://uk.bookshop.org/p/books/spot-goes-to-the-farm-eric-hill/9780723263708', NULL, '£7.99', 'in_stock', 'Board book for babies/toddlers', 'A Spot lift the flap farm board book where animal faces appear after each pause, extending the Spot looking game.', 'Farm animals give new faces inside the Spot rhythm they already know. You keep the pause and change the cast. Add the farm book when home Spot is soft and chewed at the corners. Use Spot Goes to the as the second option when the first favourite is already out.', 'Faces and feelings looking.', 'Supervise flaps and corners.', 'buy', true, 'Check shelf for duplicates.', 'High overlap with board books card; rotate rather than double buy.', 'Board book.', 'good', ARRAY[]::text[], 'none'),
    ('cat_feelings_faces_books', 10, 10, 'visible', true, true, 'Best for caterpillar face pages', 'The Very Hungry Caterpillar', 'Eric Carle', 'Bookshop.org UK', 'https://uk.bookshop.org/p/books/the-very-hungry-caterpillar-eric-carle/9780241003008', NULL, '£6.99', 'in_stock', 'Board book for babies/toddlers', 'A classic board book with a friendly caterpillar face and hole pages through fruit, inviting looking pauses while food disappears one bite at a time.', 'The caterpillar face is simple enough to notice between holes. You pause, look, then poke. Keep Caterpillar when you want a face inside a story that will still earn rereads next year. Keep the session short with The Very Hungry Caterpillar so it stays a friendly invite.', 'Faces and feelings looking.', 'Supervise flaps and corners.', 'buy', true, 'Check shelf for duplicates.', 'High overlap with board books card; rotate rather than double buy.', 'Board book.', 'good', ARRAY[]::text[], 'none'),
    ('cat_highchair', 1, 1, 'visible', true, false, 'Best for compact fold storage', 'Joie Mimzy Snacker Highchair', 'Joie', 'Boots UK', 'https://www.boots.com/joie-mimzy-snacker-highchair-abc-charcoal-10220635', NULL, '£49.90', 'in_stock', 'From about 6 months to 15kg / approx 3 years', 'A lightweight folding highchair with a large tray, wipeable pad and five point harness, made for upright meals in smaller kitchens.', 'Mealtimes are moving to the table, and a chair that folds away helps in a small kitchen. The tray and harness keep upright eating practical without a permanent frame. Choose Mimzy Snacker when storage space is the daily friction. Keep Joie Mimzy Snacker Highchair in easy reach for the next short try.', 'Upright feeding with easy storage.', 'Clean straps carefully; check harness height as they grow.', 'buy', false, 'Parent buy.', 'One highchair is enough.', 'Always harness; never leave unattended.', 'good', ARRAY[]::text[], 'check_url'),
    ('cat_highchair', 2, 2, 'visible', true, true, 'Best for recline to upright', 'Joie Mimzy Recline Highchair', 'Joie', 'Boots UK', 'https://www.boots.com/joie-mimzy-recline-highchair-arctic-10320741', NULL, '£80.00', 'in_stock', 'From birth recline; upright feeding when ready', 'A Joie highchair with multiple recline and height positions, so early sits can move into upright tray meals as they grow.', 'If weaning started early, recline positions may already be on the chair. At 10 to 12 months the job is upright meals. Pick Mimzy Recline when you want one frame that already covered the newborn sit and now locks upright.', 'Grow with me upright seat.', 'Larger than Snacker when open.', 'buy', false, NULL, 'Do not buy both Joie Mimzy models.', 'Harness always.', 'good', ARRAY[]::text[], 'check_url'),
    ('cat_highchair', 3, 3, 'visible', true, true, 'Best for a chair for years', 'Stokke Tripp Trapp High Chair', 'Stokke', 'Boots UK', 'https://www.boots.com/stokke-tripp-trapp-high-chair-natural-10116308', NULL, 'From £199', 'in_stock', 'Grows from baby set through childhood with accessories', 'An adjustable wooden Tripp Trapp chair that brings them to the family table, with baby accessories available for upright supported sitting.', 'If you want one chair at the table for years, Tripp Trapp is the long game. Budget and baby set extras count too. Choose it when you will keep the chair past toddler years and can pay for the right accessories now.', 'Table height upright seat for years.', 'Baby Set and tray often extra cost.', 'buy', false, NULL, 'Large spend; borrow first if unsure.', 'Use correct baby set; harness guidance from brand.', 'good', ARRAY[]::text[], 'check_price'),
    ('cat_highchair', 4, 4, 'visible', true, true, 'Best for multi mode value', 'Cosatto Noodle 0 Highchair', 'Cosatto', 'Boots UK', 'https://www.boots.com/cosatto-noodle-0-highchair-mister-fox-10285197', NULL, 'See Boots', 'in_stock', 'From birth / early sitting modes per listing', 'A Cosatto multi mode highchair with tray and harness options, designed to move from early sits into upright family meals.', 'UK brand multi mode chairs sit between budget fold and Tripp Trapp spend. Check the upright tray setup matches your table. Consider Noodle when you want pattern and modes without Stokke pricing. Stay nearby while they try Cosatto Noodle 0 Highchair, then stop on a good note.', 'Multi mode upright feeding.', 'Confirm current upright age guidance on listing.', 'buy', false, NULL, 'One chair only.', 'Harness; supervision.', 'good', ARRAY[]::text[], 'check_url'),
    ('cat_highchair', 5, 5, 'visible', true, true, 'Best for design led table seat', 'Bugaboo Giraffe High Chair', 'Bugaboo', 'Boots UK', 'https://www.boots.com/bugaboo-giraffe-high-chair-white-10320750', NULL, 'See Boots', 'in_stock', 'Grow with child highchair system', 'A Bugaboo Giraffe highchair system aimed at bringing them to the table with adjustable parts as they grow through toddler years.', 'Design led table seats compete with Tripp Trapp for long use. Price is high. Pick Giraffe only when the look and modular system weigh more than a simple foldaway tray chair. Put Bugaboo Giraffe High Chair where you both sit most evenings so the invite is easy.', 'Long use table seat.', 'Premium price; accessories.', 'buy', false, NULL, 'Do not stack with Tripp Trapp.', 'Follow brand baby set guidance.', 'good', ARRAY[]::text[], 'check_price'),
    ('cat_peekaboo_scarf', 1, 1, 'visible', true, false, 'Best for rainbow peekaboo', 'Baby Sensory Scarves Age 0+ UKCA (set of 7)', 'The Little Sensory Bag Co.', 'The Little Sensory Bag Co.', 'https://www.thelittlesensorybagco.co.uk/product-page/baby-sensory-scarves-age-0', NULL, 'From £2.25 each / set pricing on page', 'in_stock', 'UKCA Safety Tested as Toys from 0+', 'A set of seven rainbow organza scarves with firm hems, UKCA tested from birth, for waving, covering toys and simple peekaboo on the floor.', 'Hidden toys are a big game now, and a light scarf is kinder than a thick blanket over the face. Firm hems and dye that does not run help when the scarf ends up wet. Start with a rainbow set when you want one cloth language for hide and find.', 'Peekaboo cloth play.', 'Always supervise; never leave draped over face unsupervised.', 'buy', true, 'Light gift; easy to post.', 'One set is enough; skip duplicates.', 'Adult supervised peekaboo only.', 'good', ARRAY[]::text[], 'none'),
    ('cat_peekaboo_scarf', 2, 2, 'visible', true, true, 'Best for a giant hide cloth', 'TickiT Giant Sensory Scarf', 'TickiT', 'The Little Sensory Bag Co.', 'https://www.thelittlesensorybagco.co.uk/product-page/tickit-giant-sensory-scarf', NULL, '£4.99', 'in_stock', 'Adult supervised sensory cloth; listing notes supervision', 'A large organza sensory scarf in rainbow colours, sized for adult led peekaboo, tent play and waving games with a nearly one.', 'A bigger cloth turns peekaboo into a shared floor game you control. You lift and lower; they reach and laugh. Pick a giant scarf when the small squares are fiddly in your hands and you want one clear hide sheet for the living room.', 'Adult led peekaboo.', 'Listing stresses supervision; not for unsupervised play.', 'buy', true, 'Pair with a soft toy to hide.', 'One giant scarf is enough.', 'Strict adult supervision.', 'good', ARRAY[]::text[], 'check_age_fit'),
    ('cat_peekaboo_scarf', 3, 3, 'visible', true, true, 'Best for a single colour scarf', 'Baby Sensory Scarf single colour option', 'The Little Sensory Bag Co.', 'The Little Sensory Bag Co.', 'https://www.thelittlesensorybagco.co.uk/product-page/baby-sensory-scarves-age-0', NULL, '£2.25', 'in_stock', 'UKCA from 0+', 'A single UKCA tested organza sensory scarf sold individually, handy if you only need one colour for bag and sofa peekaboo.', 'A full set is lovely; one scarf still covers hide and find on the sofa. That helps when storage is tight or you are testing the game first. Choose a single colour when you already own a muslin and just want a lighter see through cloth.', 'Minimal peekaboo cloth.', 'Same product family as rank 1 set.', 'buy', true, 'Tiny add on gift.', 'Skip if buying the set.', 'Supervise.', 'good', ARRAY[]::text[], 'none'),
    ('cat_peekaboo_scarf', 4, 4, 'visible', true, true, 'Best for mirror shape peek', 'Hape Montessori Mirror Shape Puzzle', 'Hape', 'Hape UK', 'https://uk.hape.com/montessori-mirror-shape-puzzle-e0072', NULL, '£19.99', 'in_stock', 'From 12 months', 'A wooden shape puzzle with mirror pieces, so lifting a shape reveals a flash of their own face during shared floor play.', 'Peekaboo is not only cloth. A mirror under a shape gives the same surprise with a different object. Pick this when they already love faces in the hallway mirror and you want that same reveal waiting on the floor mat after lunch.', 'Face reveal play.', 'Glass free acrylic style mirrors; still supervise.', 'buy', true, 'Different from scarves.', 'Also overlaps pincer play.', 'Supervise.', 'good', ARRAY[]::text[], 'none'),
    ('cat_peekaboo_scarf', 5, 5, 'visible', true, true, 'Best for bringing muslins back', 'Bring back a clean muslin for peekaboo', 'Home / existing', 'Bring back out', 'https://www.thelittlesensorybagco.co.uk/product-page/baby-sensory-scarves-age-0', NULL, '£0 (use what you have)', 'in_stock', 'Household cloth under adult supervision', 'A clean muslin or light tea towel from the drawer, used only with you for short peekaboo and toy hiding games on the floor.', 'Before buying another scarf set, try the muslin you already wash weekly. The game is the pause and reveal, not the brand label. Bring a muslin back out when you want to test hide and find tonight without a parcel.', 'Bring back out before buy.', 'Never leave covering face; not a sleep aid.', 'bring_back_out', false, NULL, 'Default first step.', 'Adult only; no unsupervised covering.', 'good', ARRAY[]::text[], 'check_claim'),
    ('cat_pincer_puzzle', 1, 1, 'visible', true, false, 'Best for first big pegs', 'Hape Creative Peg Puzzle', 'Hape', 'Hape UK', 'https://uk.hape.com/creative-peg-puzzle-e0411', NULL, '£14.99', 'in_stock', 'From 12 months', 'A wooden peg puzzle with oversized first big pegs and simple shapes, sized so a nearly one can lift and drop pieces using thumb and finger.', 'Pincer work is shifting from raking grabs to deliberate lifts. First big pegs forgive wobbly aim and keep the board from becoming a pile of half fitted pieces. Start here when you want one clear peg job on the tray table after lunch.', 'Pincer peg practice.', 'Supervise; small rooms still need clear floor for dropped pieces.', 'buy', true, 'Good first peg gift.', 'One starter peg set is enough.', 'Supervise.', 'good', ARRAY[]::text[], 'none'),
    ('cat_pincer_puzzle', 2, 2, 'visible', true, true, 'Best for farm peg pictures', 'Bigjigs My First Peg Puzzle Farm', 'Bigjigs', 'Wooden Toy Shop', 'https://www.woodentoyshop.co.uk/products/my-first-peg-puzzle-farm', NULL, '£8.49', 'in_stock', '12 months +', 'A wooden farm themed first peg puzzle with chunky knobs and matching pictures under each piece for lift and name play.', 'Animal pictures under the pegs give you something to name while they lift. That turns a motor job into a short chat on the tray. Choose farm pegs when they already point at animals in books and you want the same faces on wood. This pick is farm peg pictures.', 'Peg lifts plus naming.', 'Fewer pieces than a sorter box.', 'buy', true, 'Smaller gift price.', 'Fine beside one sorter.', 'Supervise.', 'good', ARRAY[]::text[], 'none'),
    ('cat_pincer_puzzle', 3, 3, 'visible', true, true, 'Best for posting shapes', 'Hape Shape Sorting Box', 'Hape', 'Hape UK', 'https://uk.hape.com/shape-sorting-box-e0507', NULL, '£17.99', 'in_stock', 'From 12 months', 'A wooden shape sorting box with four garden creature shapes held by elastic inside, so pieces stay with the box after posting.', 'Posting through a hole is a different pincer job from lifting pegs off a board. Elastic keepers mean fewer pieces under the sofa. Pick this when they love putting things in containers and you want shapes that do not vanish. This pick is posting shapes.', 'Posting pincer practice.', 'Only four shapes.', 'buy', true, 'Good gift with clear packing.', 'Skip a second sorter box.', 'Supervise.', 'good', ARRAY[]::text[], 'none'),
    ('cat_pincer_puzzle', 4, 4, 'visible', true, true, 'Best for a posting box tray', 'Bigjigs Baby Wooden Shape Sorter Posting Box', 'Bigjigs', 'Wooden Toy Shop', 'https://www.woodentoyshop.co.uk/products/first-posting-box', NULL, '£15.99', 'in_stock', '12 months +', 'A wooden posting box with six play pieces for dropping shapes through matching holes, made for early tray table practice.', 'Six pieces give a little more variety once four shape holes are sorted quickly. The box format keeps the job contained on a highchair tray or floor mat. Choose it when Hape box stock is tight and you still want a clear posting job. This pick is a posting box tray.', 'Contained posting.', 'Pieces can still escape when the lid is off.', 'buy', true, 'Check they do not already own a sorter.', 'Medium ownership risk.', 'Supervise.', 'good', ARRAY[]::text[], 'none'),
    ('cat_pincer_puzzle', 5, 5, 'visible', true, true, 'Best for textured lift outs', 'Tidlo Touch and Feel Bug Puzzle', 'Tidlo', 'Wooden Toy Shop', 'https://www.woodentoyshop.co.uk/products/touch-and-feel-bugs', NULL, '£15.99', 'in_stock', '12 months +', 'A wooden sensory bug puzzle with textured lift out pieces, so fingers get a different feel while matching each bug to its slot.', 'Smooth pegs are useful; textured bugs add a second reason to keep lifting. That helps when plain boards lose interest after a week. Pick textured lift outs when they already mouth and stroke fabrics and you want the same curiosity on a puzzle.', 'Pincer plus texture.', 'Textures need wiping after mouthing.', 'buy', true, 'Nice sensory gift.', 'Fine as a second puzzle.', 'Supervise.', 'good', ARRAY[]::text[], 'none'),
    ('cat_push_pull_toys', 1, 1, 'visible', true, false, 'Best for steady first pushes', 'Hape My First Musical Walker', 'Hape', 'Hape UK', 'https://uk.hape.com/my-first-musical-walker-e0383', NULL, '£54.99', 'in_stock', 'From 12 months', 'A sturdy wooden push walker with a wide base, easy grip bar and a musical panel, made for early standing pushes across a clear floor.', 'Cruising is turning into short pushes, and a wide wooden base is kinder than a light plastic racer on laminate. The musical panel keeps hands busy when they pause to rest. This is the walker to start with when balance is still wobbly and you want one solid frame in the room.', 'Stable push support for getting ready to move.', 'Supervise on stairs; clear the path.', 'buy', true, 'Good gift if they are pulling to stand.', 'One solid walker is enough.', 'Adult supervision; not a sit-in walker.', 'good', ARRAY[]::text[], 'none'),
    ('cat_push_pull_toys', 2, 2, 'visible', true, true, 'Best for blocks while walking', 'Tidlo Wooden Baby Walker with ABC Blocks', 'Tidlo', 'Wooden Toy Shop', 'https://www.woodentoyshop.co.uk/products/babywalker-with-abc-blocks', NULL, '£72.99', 'in_stock', '12 months +', 'A wooden push walker with rubber edged wheels and a tray of 24 letter and number blocks, so pushing and posting share one toy.', 'Once they can push a few steps, a tray of chunky blocks turns the walker into a carry and empty job. That fits busy hands without a separate posting set yet. Choose this when you want one piece of furniture doing both push practice and floor play.', 'Push practice plus block play.', 'Loose blocks; supervise mouthing.', 'buy', true, 'Larger gift; check storage space.', 'Skip if you already own a full wooden walker.', 'Supervise; assembly required.', 'good', ARRAY[]::text[], 'none'),
    ('cat_push_pull_toys', 3, 3, 'visible', true, true, 'Best for a pull along friend', 'Hape Walk-A-Long Puppy', 'Hape', 'Hape UK', 'https://uk.hape.com/walk-a-long-puppy-e0347', NULL, '£19.99', 'in_stock', 'From 12 months', 'A wooden puppy on wheels with a string handle, sized for a nearly one who wants something to drag behind on short floor tours.', 'Push walkers help balance; a pull toy adds the opposite job of glancing back while moving. That second skill shows up once cruising is more confident. Pick this when they keep turning to check what is following them down the hall.', 'Pull as well as push.', 'Supervise string; coil away after play.', 'buy', true, 'Smaller gift than a full walker.', 'Fine beside one push walker.', 'Supervise string play.', 'good', ARRAY[]::text[], 'none'),
    ('cat_push_pull_toys', 4, 4, 'visible', true, true, 'Best for a simple push duck', 'Bigjigs Baby Wooden Duck Push Along', 'Bigjigs', 'Wooden Toy Shop', 'https://www.woodentoyshop.co.uk/products/push-along-duck', NULL, '£12.99', 'in_stock', '12 Months Plus', 'A small wooden duck on wheels with a stick handle to push across the floor, lighter than a full baby walker for short indoor routes.', 'Not every home needs a big walker on the first day of standing. A light duck on a stick lets them practise push without the bulk. This fits smaller rooms and families who already borrow a proper walker from grandparents.', 'Light push practice.', 'Less stable than a wide walker.', 'buy', true, 'Easy smaller gift.', 'Good if space is tight.', 'Supervise.', 'good', ARRAY[]::text[], 'none'),
    ('cat_push_pull_toys', 5, 5, 'visible', true, true, 'Best for a busy front board', 'Tidlo Wooden Baby Walker Activity Centre', 'Tidlo', 'Wooden Toy Shop', 'https://www.woodentoyshop.co.uk/products/activity-walker', NULL, '£59.99', 'in_stock', '12 months +', 'A wooden activity walker with a busy front board and a rear shelf for carrying a favourite toy while they push around the room.', 'Some walkers are empty frames; this one keeps beads and shapes on the front and a shelf for a soft toy behind. That matches short pushes with something to do when they pause. Choose it for curious pushers who empty baskets onto the floor.', 'Push plus busy board play.', 'More visual clutter.', 'buy', true, 'Check they do not already own a busy walker.', 'High ownership risk beside a musical walker.', 'Supervise.', 'good', ARRAY[]::text[], 'none')
  ) AS v(source_category_entity_id, pick_rank, longlist_rank, status, is_visible, is_locked, best_for_tag, product_name, brand, retailer, product_url, image_url, price_text, stock_status, age_mark_on_listing, product_description, ember_verdict, why_it_fits, caveats, buy_borrow_hold_off, gift_suitable, gift_note, ownership_note, safety_notes, evidence_tier, evidence_sources, founder_qa_flag)
)
INSERT INTO public.pl_stage3_picks (
  age_band_id,
  category_type_id,
  source_category_entity_id,
  pick_rank,
  longlist_rank,
  status,
  is_visible,
  is_locked,
  best_for_tag,
  product_name,
  brand,
  retailer,
  product_url,
  image_url,
  price_text,
  stock_status,
  age_mark_on_listing,
  product_description,
  ember_verdict,
  why_it_fits,
  caveats,
  buy_borrow_hold_off,
  gift_suitable,
  gift_note,
  ownership_note,
  safety_notes,
  evidence_tier,
  evidence_sources,
  founder_qa_flag,
  research_payload
)
SELECT
  '9-12m',
  ct.id,
  r.source_category_entity_id,
  r.pick_rank,
  r.longlist_rank,
  r.status,
  r.is_visible,
  r.is_locked,
  r.best_for_tag,
  r.product_name,
  r.brand,
  r.retailer,
  r.product_url,
  r.image_url,
  r.price_text,
  r.stock_status,
  r.age_mark_on_listing,
  r.product_description,
  r.ember_verdict,
  r.why_it_fits,
  r.caveats,
  r.buy_borrow_hold_off,
  r.gift_suitable,
  r.gift_note,
  r.ownership_note,
  r.safety_notes,
  r.evidence_tier,
  r.evidence_sources,
  r.founder_qa_flag,
  jsonb_build_object(
    'bundle_schema_version', 'stage3_ingestion_bundle_v1',
    'bundle_generated_at', '2026-07-24T11:05:59.281Z',
    'research_schema_version', 'ember_picks_research_v3',
    'source_category_entity_id', r.source_category_entity_id
  )
FROM stage3_rows r
JOIN public.pl_category_types ct
  ON ct.slug = r.source_category_entity_id
WHERE EXISTS (
  SELECT 1
  FROM public.pl_age_band_development_need_category_types abdnct
  WHERE abdnct.age_band_id = '9-12m'
    AND abdnct.category_type_id = ct.id
    AND abdnct.is_active = true
);

